import Foundation

struct CategoryContent15 {
    static let aiSafetyYou = CategoryData(
        id: "ai_safety_you", name: "AI Safety & You", icon: "shield.fill", colorName: "aiRed",
        description: "Stay safe and smart in a world powered by AI",
        lessons: [lesson1, lesson2, lesson3, lesson4, lesson5, lesson6], order: 14,
        unlockRequirement: .none
    )

    static let lesson1 = LessonData(id: "asy_l1", title: "Your Data & AI", description: "What happens when you type into AI", categoryId: "ai_safety_you", questions: [
        Question(id: "asy1_q1", type: .multipleChoice, questionText: "When you type something into an AI chatbot, what could happen to that information?", options: ["It may be stored and used to improve the AI model", "It is immediately and permanently deleted", "It is sent directly to the government", "It is printed out at the AI company's office"], correctAnswer: "It may be stored and used to improve the AI model", explanation: "Many AI services may store your conversations to improve their models. Privacy policies vary by company, so always check what happens to your data before sharing sensitive information."),
        Question(id: "asy1_q2", type: .trueFalse, questionText: "It is safe to share your home address, phone number, and passwords with an AI chatbot.", options: ["True", "False"], correctAnswer: "False", explanation: "Never share personal identifying information, passwords, or financial details with AI chatbots. This data could be stored, leaked, or accessed by others."),
        Question(id: "asy1_q3", type: .sortOrder, questionText: "Rank these from SAFEST to MOST RISKY to share with an AI chatbot:", options: ["Your credit card number", "Your social security number", "A general homework question", "Your full name and school"], correctAnswers: ["A general homework question", "Your full name and school", "Your credit card number", "Your social security number"], explanation: "General questions carry minimal risk. Personal details carry increasing risk, with financial and identity information being the most dangerous to share."),
        Question(id: "asy1_q4", type: .scenarioJudgment, questionText: "Your friend says they told an AI chatbot their home address to get directions. Was this a good idea?", options: ["No, use a maps app instead of sharing your address with a chatbot", "Yes, AI chatbots need your address to help you", "It depends on which chatbot they used"], correctAnswer: "No, use a maps app instead of sharing your address with a chatbot", explanation: "Dedicated maps apps are designed to handle location data securely. Sharing your home address with a general AI chatbot is unnecessary and creates a privacy risk."),
        Question(id: "asy1_q5", type: .fillInBlank, questionText: "Before sharing information with an AI tool, you should read the company's __________ policy.", options: ["privacy", "refund", "marketing", "hiring"], correctAnswer: "privacy", explanation: "Privacy policies explain how your data is collected, stored, and used. Understanding them helps you make informed decisions about what to share with AI tools."),
        Question(id: "asy1_q6", type: .multipleChoice, questionText: "Which of these is the SAFEST type of information to share with an AI chatbot?", options: ["A general knowledge question about science", "Your email password", "A photo of your passport", "Your parent's credit card number"], correctAnswer: "A general knowledge question about science", explanation: "General knowledge questions do not reveal personal information. Always avoid sharing passwords, identity documents, or financial information with AI tools.")
    ], order: 0, difficulty: .beginner)

    static let lesson2 = LessonData(id: "asy_l2", title: "Spotting Deepfakes", description: "How to tell real from AI-generated content", categoryId: "ai_safety_you", questions: [
        Question(id: "asy2_q1", type: .multipleChoice, questionText: "What is a 'deepfake'?", options: ["AI-generated media that looks or sounds like a real person", "A very deep website on the internet", "A type of computer virus", "A fake social media account run by a human"], correctAnswer: "AI-generated media that looks or sounds like a real person", explanation: "Deepfakes use AI to create realistic-looking videos, images, or audio of people saying or doing things they never actually did, raising serious concerns about misinformation."),
        Question(id: "asy2_q2", type: .trueFalse, questionText: "Deepfake technology can only create fake videos, not fake audio.", options: ["True", "False"], correctAnswer: "False", explanation: "Deepfake technology can create fake videos, images, AND audio. AI voice cloning can replicate someone's voice from just a few seconds of sample audio, making fake phone calls possible."),
        Question(id: "asy2_q3", type: .matchPairs, questionText: "Match each deepfake clue to what to look for:", matchPairs: [
            MatchPair(term: "Unnatural blinking", definition: "Eyes move strangely or rarely"),
            MatchPair(term: "Audio sync issues", definition: "Lips don't match the words"),
            MatchPair(term: "Skin texture", definition: "Too smooth or oddly blurred"),
            MatchPair(term: "Background glitches", definition: "Warping or inconsistent edges")
        ], explanation: "While deepfakes are improving rapidly, these visual and audio clues can still help you spot many AI-generated fakes, especially in video content."),
        Question(id: "asy2_q4", type: .scenarioJudgment, questionText: "You see a video of a celebrity endorsing a product that seems out of character for them. Could this be a deepfake?", options: ["Yes, be skeptical and verify through official channels", "No, videos are always real", "Only if the video quality is poor"], correctAnswer: "Yes, be skeptical and verify through official channels", explanation: "Deepfake celebrity endorsements are a growing problem. Always verify unusual celebrity endorsements through official social media accounts or trusted news sources."),
        Question(id: "asy2_q5", type: .fillInBlank, questionText: "AI-generated images often struggle with accurately rendering human __________, sometimes showing extra fingers or distorted shapes.", options: ["hands", "shirts", "shadows", "haircuts"], correctAnswer: "hands", explanation: "Hands remain one of the most challenging features for AI image generators. Look for extra fingers, merged digits, or unnatural hand positions as signs of AI-generated images."),
        Question(id: "asy2_q6", type: .multipleChoice, questionText: "Why are deepfakes becoming harder to detect over time?", options: ["AI generation technology is rapidly improving in quality", "People are getting worse at looking at images", "Screen resolutions are decreasing", "Deepfakes are now made by hand instead of AI"], correctAnswer: "AI generation technology is rapidly improving in quality", explanation: "As AI models improve, deepfakes become increasingly realistic. This is why media literacy and verification skills are more important than ever.")
    ], order: 1, difficulty: .beginner)

    static let lesson3 = LessonData(id: "asy_l3", title: "AI & Your Emotions", description: "Understanding the limits of AI relationships", categoryId: "ai_safety_you", questions: [
        Question(id: "asy3_q1", type: .multipleChoice, questionText: "Why might someone start to feel like an AI chatbot is their friend?", options: ["AI is designed to respond in a friendly, empathetic way", "AI chatbots genuinely care about users' feelings", "AI forms real emotional bonds with frequent users", "AI chatbots remember everything about you permanently"], correctAnswer: "AI is designed to respond in a friendly, empathetic way", explanation: "AI chatbots are designed to be engaging and pleasant, which can feel like genuine friendship. However, AI does not have feelings or form real relationships — it is generating helpful responses."),
        Question(id: "asy3_q2", type: .trueFalse, questionText: "AI chatbots can truly understand and feel your emotions the way a human friend can.", options: ["True", "False"], correctAnswer: "False", explanation: "AI processes language patterns to generate appropriate responses, but it does not experience emotions or empathy. A supportive-sounding response is generated through pattern matching, not genuine feeling."),
        Question(id: "asy3_q3", type: .scenarioJudgment, questionText: "A friend tells you they prefer talking to an AI chatbot about their problems instead of talking to real people. Should you be concerned?", options: ["Yes, gently encourage them to also talk to real people", "No, AI is a perfect replacement for human connection", "It depends on the AI model they use"], correctAnswer: "Yes, gently encourage them to also talk to real people", explanation: "While AI can be a useful tool, it should not replace human relationships. Real human connection, empathy, and support are essential for emotional wellbeing."),
        Question(id: "asy3_q4", type: .fillInBlank, questionText: "A __________ relationship is a one-sided bond where one person feels connected to someone (or something) that does not truly know them.", options: ["parasocial", "reciprocal", "professional", "biological"], correctAnswer: "parasocial", explanation: "Parasocial relationships with AI chatbots are a growing concern. The AI's friendly responses can create an illusion of mutual connection that does not actually exist."),
        Question(id: "asy3_q5", type: .matchPairs, questionText: "Match each statement to whether it describes a healthy or unhealthy AI interaction:", matchPairs: [
            MatchPair(term: "Using AI for homework help", definition: "Healthy interaction"),
            MatchPair(term: "Replacing all friends with AI", definition: "Unhealthy interaction"),
            MatchPair(term: "Asking AI to brainstorm ideas", definition: "Healthy interaction"),
            MatchPair(term: "Believing AI truly loves you", definition: "Unhealthy interaction")
        ], explanation: "AI is a powerful tool when used appropriately, but believing it can replace genuine human relationships or has real feelings can be harmful to your wellbeing."),
        Question(id: "asy3_q6", type: .multipleChoice, questionText: "What is one reason AI companies design chatbots to sound friendly and empathetic?", options: ["It makes the product more engaging and useful", "The AI genuinely develops a personality over time", "It is required by law in most countries", "The AI learns emotions from its microphone"], correctAnswer: "It makes the product more engaging and useful", explanation: "Friendly, empathetic responses make AI tools more pleasant and effective to use. This is a design choice, not evidence that the AI has real feelings or cares about you.")
    ], order: 2, difficulty: .intermediate)

    static let lesson4 = LessonData(id: "asy_l4", title: "Scams & AI Tricks", description: "Recognizing AI-powered fraud and deception", categoryId: "ai_safety_you", questions: [
        Question(id: "asy4_q1", type: .multipleChoice, questionText: "How can scammers use AI voice cloning technology?", options: ["To impersonate a family member asking for money over the phone", "To improve the sound quality of legitimate phone calls", "To translate phone calls into other languages", "To block spam calls automatically"], correctAnswer: "To impersonate a family member asking for money over the phone", explanation: "AI voice cloning can replicate someone's voice from just a short sample. Scammers use this to call victims pretending to be a family member in an emergency, asking for money."),
        Question(id: "asy4_q2", type: .trueFalse, questionText: "AI can be used to write more convincing phishing emails that are harder to spot than traditional scam messages.", options: ["True", "False"], correctAnswer: "True", explanation: "AI can generate grammatically perfect, personalized phishing emails without the spelling errors and awkward phrasing that traditionally helped people spot scams."),
        Question(id: "asy4_q3", type: .sortOrder, questionText: "Put these steps in the right order for verifying a suspicious call from someone claiming to be a family member:", options: ["Call the family member back on their known number", "Do NOT send money or share personal information", "Hang up the suspicious call", "Ask a trusted adult for help if unsure"], correctAnswers: ["Do NOT send money or share personal information", "Hang up the suspicious call", "Call the family member back on their known number", "Ask a trusted adult for help if unsure"], explanation: "When you receive a suspicious call, the priority is to avoid sending money, end the suspicious call, verify independently through a known contact method, and seek help."),
        Question(id: "asy4_q4", type: .scenarioJudgment, questionText: "You receive an email that looks exactly like it is from your bank, asking you to click a link and verify your account. The grammar is perfect and the formatting looks real. Could this be an AI-generated scam?", options: ["Yes, AI makes phishing emails more convincing than ever", "No, perfect grammar means it is legitimate", "Only if the email has spelling errors"], correctAnswer: "Yes, AI makes phishing emails more convincing than ever", explanation: "AI-generated phishing emails can perfectly mimic legitimate communications. Always verify by contacting your bank directly through official channels, never through links in emails."),
        Question(id: "asy4_q5", type: .fillInBlank, questionText: "AI-powered __________ scams use fake but realistic video calls to impersonate bosses, colleagues, or officials.", options: ["deepfake", "download", "desktop", "database"], correctAnswer: "deepfake", explanation: "Deepfake video scams have been used in real cases where criminals impersonated executives in video calls to authorize fraudulent money transfers worth millions."),
        Question(id: "asy4_q6", type: .multipleChoice, questionText: "What is the BEST defense against AI-powered scams?", options: ["Always verify identity through a separate, trusted channel", "Never use the internet or phone again", "Trust anyone who sounds familiar on the phone", "Rely on your email spam filter to catch everything"], correctAnswer: "Always verify identity through a separate, trusted channel", explanation: "Independent verification is your strongest defense. If someone asks for money or sensitive information, verify their identity by contacting them through a known, separate method.")
    ], order: 3, difficulty: .intermediate)

    static let lesson5 = LessonData(id: "asy_l5", title: "Think Before You Trust", description: "Critical thinking in the age of AI", categoryId: "ai_safety_you", questions: [
        Question(id: "asy5_q1", type: .multipleChoice, questionText: "Why is AI confidence NOT a reliable indicator of accuracy?", options: ["AI generates responses with equal confidence whether correct or wrong", "AI always warns you when it is unsure", "Confident AI responses are always fact-checked first", "AI only responds when it is certain of the answer"], correctAnswer: "AI generates responses with equal confidence whether correct or wrong", explanation: "AI models do not have a reliable sense of their own accuracy. They can state completely false information with the same confident tone as verified facts."),
        Question(id: "asy5_q2", type: .trueFalse, questionText: "Just because information appears in an AI-generated response does not mean it is true.", options: ["True", "False"], correctAnswer: "True", explanation: "AI models generate plausible-sounding text based on patterns in training data. They can produce false information, outdated facts, or entirely fabricated details that sound convincing."),
        Question(id: "asy5_q3", type: .matchPairs, questionText: "Match each critical thinking skill to how it helps with AI:", matchPairs: [
            MatchPair(term: "Source verification", definition: "Check if AI claims have real backing"),
            MatchPair(term: "Logical reasoning", definition: "Spot contradictions in AI output"),
            MatchPair(term: "Healthy skepticism", definition: "Question confident-sounding claims"),
            MatchPair(term: "Cross-referencing", definition: "Compare AI answers with other sources")
        ], explanation: "Critical thinking skills are your most powerful tools for navigating AI-generated content responsibly and avoiding misinformation."),
        Question(id: "asy5_q4", type: .scenarioJudgment, questionText: "An AI confidently tells you that a particular medication is safe to take with your other prescriptions. Should you trust this advice?", options: ["No, always consult a real doctor for medical advice", "Yes, AI has access to all medical knowledge", "It depends on which AI you asked"], correctAnswer: "No, always consult a real doctor for medical advice", explanation: "AI should never be relied upon for medical advice. AI models can provide incorrect or dangerous medical information. Always consult qualified healthcare professionals for health decisions."),
        Question(id: "asy5_q5", type: .fillInBlank, questionText: "The ability to think __________ about information — questioning its source, accuracy, and intent — is essential in the age of AI.", options: ["critically", "quickly", "emotionally", "randomly"], correctAnswer: "critically", explanation: "Critical thinking means evaluating information carefully rather than accepting it at face value. This skill becomes even more important as AI-generated content becomes more prevalent."),
        Question(id: "asy5_q6", type: .multipleChoice, questionText: "Which approach is BEST when using AI for an important decision?", options: ["Use AI as one input among several, including expert advice", "Let AI make the final decision for you", "Ignore AI entirely and rely on gut feeling alone", "Ask AI the same question ten times and go with the majority answer"], correctAnswer: "Use AI as one input among several, including expert advice", explanation: "For important decisions, AI should be one of many inputs. Combine AI insights with expert advice, your own research, and critical thinking for the best outcomes.")
    ], order: 4, difficulty: .advanced)

    static let lesson6 = LessonData(id: "asy_l6", title: "Being a Responsible AI User", description: "Using AI without hurting others", categoryId: "ai_safety_you", questions: [
        Question(id: "asy6_q1", type: .multipleChoice, questionText: "Why is it important to be honest about when you have used AI to help create something?", options: ["It maintains trust and gives proper credit for work", "AI companies require you to tell everyone by law", "It makes your work seem more impressive", "There is no reason to disclose AI use ever"], correctAnswer: "It maintains trust and gives proper credit for work", explanation: "Honesty about AI use builds trust in personal, academic, and professional relationships. It also helps others understand the role AI played in creating the work."),
        Question(id: "asy6_q2", type: .trueFalse, questionText: "Using AI to generate an image in the style of a specific living artist without permission raises ethical concerns.", options: ["True", "False"], correctAnswer: "True", explanation: "Creating AI art that mimics a specific living artist's style raises concerns about copyright, fair compensation, and respect for the artist's creative work and livelihood."),
        Question(id: "asy6_q3", type: .scenarioJudgment, questionText: "You want to use AI to create a fake image of a classmate in an embarrassing situation as a joke. Is this okay?", options: ["No, creating fake images of real people can cause serious harm", "Yes, if it is just meant as a joke", "It depends on how realistic the image looks"], correctAnswer: "No, creating fake images of real people can cause serious harm", explanation: "Creating fake images of real people without consent is harmful and potentially illegal, regardless of intent. It can cause emotional distress, damage reputations, and constitute harassment."),
        Question(id: "asy6_q4", type: .matchPairs, questionText: "Match each responsible AI practice to its benefit:", matchPairs: [
            MatchPair(term: "Disclosing AI use", definition: "Maintains honesty and trust"),
            MatchPair(term: "Respecting copyright", definition: "Protects creators' rights"),
            MatchPair(term: "Verifying AI output", definition: "Prevents spreading misinformation"),
            MatchPair(term: "Protecting privacy", definition: "Keeps personal data safe")
        ], explanation: "Responsible AI use combines honesty, respect for others' rights, accuracy, and privacy protection to ensure AI benefits everyone."),
        Question(id: "asy6_q5", type: .fillInBlank, questionText: "When sharing AI-generated content online, responsible users provide __________ so others know it was created with AI.", options: ["attribution", "passwords", "downloads", "advertisements"], correctAnswer: "attribution", explanation: "Attribution means clearly indicating that content was AI-generated or AI-assisted. This helps others evaluate the content appropriately and maintains transparency."),
        Question(id: "asy6_q6", type: .multipleChoice, questionText: "What is a key principle of responsible AI use?", options: ["Consider how your AI use affects other people", "Use AI as much as possible for everything", "Keep your AI use secret from everyone", "Assume AI output is always fair and unbiased"], correctAnswer: "Consider how your AI use affects other people", explanation: "Responsible AI use means thinking about the broader impact — on creators, on people depicted in AI content, on those who might be affected by AI-generated misinformation, and on society as a whole.")
    ], order: 5, difficulty: .advanced)
}
